  ('aviation-f975d768-moex-00100', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '依勞動基準法第59條規定，下列何者非該條所定之補償項目？', '["醫療費用", "原領工資", "精神慰撫金", "失能補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00101', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '全民健康保險法第53條關於不予給付之事由，下列何者非屬之？', '["違反本保險規定之有關就醫程序", "住院治療經診斷並通知出院，而繼續住院之部分", "使用經事前審查，非屬醫療必要之診療服務或藥物", "因犯罪行為而受傷者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00102', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '下列有關性別工作平等法之敘述，何者正確？', '["該法所稱薪資，係包括以實物方式給付之獎金、津貼及其他任何名義之經常性給與", "該法所稱之求職者，係指受雇主僱用從事工作獲致薪資者", "該法所稱雇主，係指僱用受僱者之私立機構或機關，而不包括公立機構或機關", "該法所稱要派單位，係指從事勞動派遣業務之事業單位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00103', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '下列情形何者符合性別工作平等法第10條有關同工（值）同酬之規定？', '["甲男與乙女在A公司從事相同之搬運工作，A公司認為男性負重能力較佳，同樣從事搬運工作，男 性員工之貢獻當然比女性員工為多，因此，甲男每月工資較乙女多3,000元", "丙男與丁女在B公司從事清潔工作，B公司因認為男性體力較佳，故丙男每月工資較丁女多3,000元。 丁女不服，認為B公司之薪資政策違反同工同酬規定，要求B公司改善，否則即會到地方主管機關申 訴。B公司為避免受罰，因此調降丙男之工資，使丙男與丁女領取相同之工資", "戊男與己女在C公司從事相同工作，但「戊男」有主管頭銜，即便兩人工作價值相同，C公司仍得給 予戊男較高之薪資", "庚男與辛女在D公司從事相同工作，但庚男有碩士學位，辛女僅大學畢業，D公司得給予庚男較高 的起薪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00104', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '依司法院大法官解釋意旨，有關平等原則，下列敘述何者錯誤？', '["色盲者不得取得警察大學碩士班之入學資格，未違反平等原則", "非視障者不能從事按摩業，與所欲保障視障者工作權而生之就業利益相較，顯不相當，違反平等原則", "政府採購得標廠商於國內員工總人數逾100人者，應於履約期間僱用一定比例之原住民，違反平等原則", "祭祀公業條例施行前已存在之祭祀公業，以規約排除女子為派下員，未違反憲法保障性別平等之意旨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00105', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '行政執行法第3條規定，行政執行應以適當之方法為之，不得逾達成執行目的之必要限度，此為下列 何種原則之展現？', '["誠實信用原則", "不當聯結禁止原則", "預見可能性原則", "比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00106', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '人民為開設餐廳而向地方政府經濟發展局申請商業登記，惟主管機關以負責人仍欠繳交通違規罰鍰為 由，拒絕當事人申請。此舉應屬違反下列何者？', '["比例原則", "誠實信用原則", "明確性原則", "不當聯結禁止原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
  ('aviation-f975d768-moex-00107', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '有關大學自治，下列敘述何者錯誤？', '["大學於教學研究相關之範圍內，就其內部組織應享有相當程度之自主組織權", "大學得自行制定章則，對成績未達一定標準之學生予以退學處分", "大學對學生所為處分若未剝奪其學生身分，行政法院必須尊重大學自治而不應受理救濟", "大學就入學資格條件所訂定之自治規章，在不違背自治權範圍內，不生違反法律保留原則之問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL)
